    <rect x="20" y="80" width="320" height="130" rx="10" fill="#18181b" stroke="#27272a"/>
    <text x="40" y="115" fill="#9945FF" font-size="15" font-weight="700" font-family="sans-serif">3 New Listings</text>
    <text x="40" y="145" fill="#fafafa" font-size="14" font-family="sans-serif">SpaceX · Micron · SanDisk</text>
    <text x="40" y="175" fill="#71717a" font-size="12" font-family="sans-serif">1:1 backed by shares in custody</text>
